/**
 * @fileoverview Fieldset barrel.
 * @module module/Fieldset
 */
import { default as razyui } from '../index.js';
import { FieldsetDef as DEF } from './Fieldset.def.js';
import Fieldset from './Fieldset/index.js';

razyui.Fieldset = Fieldset;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Fieldset);
}

export default Fieldset;

export const stylesheet = null;
