/**
 * @fileoverview Fieldset constants.
 * @module module/Fieldset/constants
 */

import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:        'fieldset',
    LEGEND:      'fieldset-legend',
    DESCRIPTION: 'fieldset-description',
    BODY:        'fieldset-body',
    DISABLED:    'is-disabled',
});

export const DEFAULTS = Object.freeze({});

export const PART = defineParts('Fieldset', {
    ROOT:        { class: 'fieldset-root', aliases: ['root', 'fieldset'] },
    LEGEND:      { class: 'fieldset-legend', aliases: ['legend'] },
    DESCRIPTION: { class: 'fieldset-description', aliases: ['description', 'desc'] },
    BODY:        { class: 'fieldset-body', aliases: ['body'] },
});

PART.ROOT.jit        = 'flex flex-col gap-[var(--fs-gap)] [border:none] p-0 m-0 {is-disabled}:opacity-50 {is-disabled}:pointer-events-none';
PART.LEGEND.jit      = 'text-[var(--fs-legend-size)] font-semibold fg-[var(--fs-legend-text)] p-0';
PART.DESCRIPTION.jit = 'text-[var(--fs-desc-size)] fg-[var(--fs-desc-text)]';
PART.BODY.jit        = 'flex flex-col gap-[var(--fs-body-gap)]';
